1	import { useState, useEffect } from "react";
2	import { View, Text } from "@tarojs/components";
3	import Taro, { useDidShow } from "@tarojs/taro";
4	import { apiFetch, getToday, formatDate, getDomains } from "../../lib";
5	import Icon, { IconName } from "../../components/Icon";
6	import "./index.scss";
7	
8	interface Habit {
9	  id: string;
10	  title: string;
11	  description: string | null;
12	  domainId: string;
13	  unit: string;
14	  targetValue: number;
15	  isActive: boolean;
16	  logs?: { date: string; completed: boolean; value: number }[];
17	}
18	
19	interface DailyGoal {
20	  title: string;
21	  detail: string;
22	  reason: string;
23	}
24	
25	export default function IndexPage() {
26	  const [habits, setHabits] = useState<Habit[]>([]);
27	  const [loading, setLoading] = useState(true);
28	  const [dailyGoals, setDailyGoals] = useState<DailyGoal[]>([]);
29	  const [goalsLoading, setGoalsLoading] = useState(false);
30	  const [goalsExpanded, setGoalsExpanded] = useState<Set<number>>(new Set());
31	  const [goalsDismissed, setGoalsDismissed] = useState(false);
32	
33	  useDidShow(() => {
34	    fetchHabits();
35	    checkDismissed();
36	    fetchDailyGoals();
37	  });
38	
39	  function checkDismissed() {
40	    const dismissedDate = Taro.getStorageSync("goals_dismissed_date");
41	    setGoalsDismissed(dismissedDate === getToday());
42	  }
43	
44	  async function fetchHabits() {
45	    try {
46	      const data = await apiFetch("/api/habits?date=" + getToday());
47	      setHabits(data);
48	    } catch {
49	      Taro.showToast({ title: "获取今日习惯失败", icon: "none" });
50	    }
51	    setLoading(false);
52	  }
53	
54	  async function fetchDailyGoals() {
55	    setGoalsLoading(true);
56	    try {
57	      const data = await apiFetch("/api/insights", {
58	        method: "POST",
59	        body: JSON.stringify({ type: "daily-goals" }),
60	      });
61	      setDailyGoals(data?.goals || []);
62	    } catch {
63	      setDailyGoals([]);
64	    }
65	    setGoalsLoading(false);
66	  }
67	
68	  async function toggleHabit(habitId: string) {
69	    try {
70	      await apiFetch("/api/logs", {
71	        method: "POST",
72	        body: JSON.stringify({ habitId, date: getToday() }),
73	      });
74	      fetchHabits();
75	    } catch {
76	      Taro.showToast({ title: "打卡失败", icon: "none" });
77	    }
78	  }
79	
80	  function toggleGoalExpand(idx: number) {
81	    setGoalsExpanded((prev) => {
82	      const next = new Set(prev);
83	      if (next.has(idx)) {
84	        next.delete(idx);
85	      } else {
86	        next.add(idx);
87	      }
88	      return next;
89	    });
90	  }
91	
92	  function dismissGoals() {
93	    Taro.setStorageSync("goals_dismissed_date", getToday());
94	    setGoalsDismissed(true);
95	  }
96	
97	  const completedCount = habits.filter(
98	    (h) => h.logs?.length && h.logs[0]?.completed
99	  ).length;
100	  const totalCount = habits.filter((h) => h.isActive).length;
101	  const progressPct = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;
102	
103	  function renderGoalsBlock() {
104	    if (goalsDismissed) return null;
105	    if (goalsLoading) {
106	      return (
107	        <View className="goals-card">
108	          <View className="goals-header">
109	            <Icon name="clipboard-list" size={40} color="accent" />
110	            <Text className="goals-title">今日建议目标</Text>
111	          </View>
112	          <View className="skeleton-lines">
113	            <View className="skeleton-line w-80" />
114	            <View className="skeleton-line w-60" />
115	          </View>
116	        </View>
117	      );
118	    }
119	    if (!dailyGoals || dailyGoals.length === 0) return null;
120	
121	    return (
122	      <View className="goals-card">
123	        <View className="goals-header">
124	          <Icon name="clipboard-list" size={40} color="accent" />
125	          <Text className="goals-title">今日建议目标</Text>
126	          <View className="goals-dismiss" onClick={dismissGoals}>
127	            <Icon name="x" size={32} />
128	          </View>
129	        </View>
130	        {dailyGoals.map((goal, idx) => {
131	          const expanded = goalsExpanded.has(idx);
132	          return (
133	            <View
134	              key={idx}
135	              className={`goals-item ${expanded ? "expanded" : ""}`}
136	              onClick={() => toggleGoalExpand(idx)}
137	            >
138	              <View className="goals-item-header">
139	                <Text className="goals-item-title">{goal.title}</Text>
140	                <Text className="goals-item-arrow">{expanded ? "▲" : "▼"}</Text>
141	              </View>
142	              {expanded && (
143	                <View className="goals-item-body">
144	                  <Text className="goals-item-detail">{goal.detail}</Text>
145	                  <Text className="goals-item-reason">理由：{goal.reason}</Text>
146	                </View>
147	              )}
148	            </View>
149	          );
150	        })}
151	      </View>
152	    );
153	  }
154	
155	  return (
156	    <View className="page">
157	      <Text className="header-date">{formatDate(new Date())}</Text>
158	      <Text className="header-title">今日日课</Text>
159	
160	      {renderGoalsBlock()}
161	
162	      <View className="progress-card">
163	        <View className="progress-ring">
164	          <View style={{
165	            width: "140rpx", height: "140rpx", borderRadius: "50%",
166	            background: `conic-gradient(#c4843e ${progressPct * 3.6}deg, #332e28 0deg)`,
167	            display: "flex", alignItems: "center", justifyContent: "center"
168	          }}>
169	            <View style={{
170	              width: "110rpx", height: "110rpx", borderRadius: "50%",
171	              background: "#221e1a", display: "flex", alignItems: "center", justifyContent: "center"
172	            }}>
173	              <Text className="progress-pct">{progressPct}%</Text>
174	            </View>
175	          </View>
176	        </View>
177	        <View className="progress-info">
178	          <Text className="progress-num">{completedCount}/{totalCount}</Text>
179	          <Text className="progress-label">今日已完成</Text>
180	        </View>
181	      </View>
182	
183	      {getDomains().map((domain) => {
184	        const domainHabits = habits.filter((h) => h.domainId === domain.name && h.isActive);
185	        if (domainHabits.length === 0) return null;
186	        return (
187	          <View key={domain.name}>
188	            <View className="domain-title-row">
189	              <Icon name={domain.icon as IconName} size={36} color="accent" />
190	              <Text className="domain-title">{domain.name}</Text>
191	            </View>
192	            {domainHabits.map((habit) => {
193	              const done = !!(habit.logs?.length && habit.logs[0]?.completed);
194	              return (
195	                <View
196	                  key={habit.id}
197	                  className={`habit-item ${done ? "done" : ""}`}
198	                  onClick={() => toggleHabit(habit.id)}
199	                >
200	                  <View className={`check-icon ${done ? "checked" : ""}`}>
201	                    {done && <Icon name="check" size={32} color="accent" />}
202	                  </View>
203	                  <View className="habit-text">
204	                    <Text className={`habit-name ${done ? "done" : ""}`}>{habit.title}</Text>
205	                    {habit.description && <Text className="habit-desc">{habit.description}</Text>}
206	                  </View>
207	                  <Text className="habit-unit">{habit.targetValue}{habit.unit}</Text>
208	                </View>
209	              );
210	            })}
211	          </View>
212	        );
213	      })}
214	
215	      {totalCount === 0 && (
216	        <View className="empty">
217	          <Text>还没有习惯</Text>
218	          <Text>去「习惯」页面添加吧</Text>
219	        </View>
220	      )}
221	    </View>
222	  );
223	}
