106	
107	.split-label {
108	  display: block;
109	  font-size: 20rpx;
110	  color: var(--color-text-muted);
111	  margin-bottom: var(--space-sm);
112	  letter-spacing: 0.04em;
113	  text-transform: uppercase;
114	}
115	
116	.split-text {
117	  display: block;
118	  font-size: var(--text-sm);
119	  color: var(--color-text-primary);
120	  line-height: 1.6;
121	}
122	
123	/* ---- 提交按钮 ---- */
124	.submit-btn {
125	  width: 100%;
126	  height: 88rpx;
127	  border-radius: var(--radius-md);
128	  background: var(--color-accent);
129	  color: var(--color-text-inverse);
130	  font-size: var(--text-md);
