1	import { useState } from "react";
2	import { View, Text } from "@tarojs/components";
3	import Taro, { useDidShow } from "@tarojs/taro";
4	import { apiFetch, getToday, getDomains } from "../../lib";
5	import Icon from "../../components/Icon";
6	import "./index.scss";
7	
8	interface HabitWithLogs {
9	  id: string;
10	  title: string;
11	  domainId: string;
12	  frequency: string;
13	  logs: { date: string; completed: boolean }[];
14	}
15	
16	export default function StatsPage() {
17	  const [habits, setHabits] = useState<HabitWithLogs[]>([]);
18	  const [loading, setLoading] = useState(true);
19	  const [range, setRange] = useState<"week" | "month">("week");
20	
21	  useDidShow(() => { fetchStats(); });
22	
23	  async function fetchStats() {
24	    try {
25	      const data = await apiFetch(`/api/stats?range=${range}`);
26	      setHabits(data.habits || []);
27	    } catch {
28	      Taro.showToast({ title: "获取统计数据失败", icon: "none" });
29	    }
30	    setLoading(false);
31	  }
32	
33	  const totalChecks = habits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
34	  const totalPossible = habits.reduce((sum, h) => {
35	    const days = range === "week" ? 7 : 30;
36	    if (h.frequency === "daily") return sum + days;
37	    if (h.frequency === "weekly") return sum + Math.ceil(days / 7);
38	    if (h.frequency === "weekday") return sum + countWeekdays(days);
39	    return sum + days;
40	  }, 0);
41	  const overallRate = totalPossible > 0 ? Math.round((totalChecks / totalPossible) * 100) : 0;
42	
43	  const domainStats = getDomains().map((d) => {
44	    const domainHabits = habits.filter((h) => h.domainId === d.name);
45	    const completed = domainHabits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
46	    const possible = domainHabits.reduce((sum, h) => {
47	      const days = range === "week" ? 7 : 30;
48	      if (h.frequency === "daily") return sum + days;
49	      if (h.frequency === "weekly") return sum + Math.ceil(days / 7);
50	      if (h.frequency === "weekday") return sum + countWeekdays(days);
51	      return sum + days;
52	    }, 0);
53	    return { name: d.name, icon: d.icon, rate: possible > 0 ? Math.round((completed / possible) * 100) : 0, color: d.color };
54	  });
55	
56	  // Bar chart data
57	  const days = range === "week" ? 7 : 30;
58	  const barData = Array.from({ length: days }, (_, i) => {
59	    const d = new Date();
60	    d.setDate(d.getDate() - (days - 1 - i));
61	    const dateStr = d.toISOString().split("T")[0];
62	    const completed = habits.filter((h) => h.logs.some((l) => l.date === dateStr && l.completed)).length;
63	    const maxH = habits.length || 1;
64	    return {
65	      label: d.toLocaleDateString("zh-CN", { day: "numeric" }),
66	      completed,
67	      pct: Math.round((completed / maxH) * 100),
68	    };
69	  });
70	
71	  const streakDays = calcStreak(habits);
72	
73	  return (
74	    <View className="page">
75	      <Text className="page-title">数据统计</Text>
76	      <Text className="page-subtitle">看见进步，持续精进</Text>
77	
78	      <View className="range-tabs">
79	        <Text className={`range-tab ${range === "week" ? "active" : ""}`} onClick={() => { setRange("week"); fetchStats(); }}>本周</Text>
80	        <Text className={`range-tab ${range === "month" ? "active" : ""}`} onClick={() => { setRange("month"); fetchStats(); }}>本月</Text>
81	      </View>
82	
83	      <View className="metrics">
84	        <View className="metric"><Text className="metric-value">{overallRate}%</Text><Text className="metric-label">总完成率</Text></View>
85	        <View className="metric"><Text className="metric-value">{totalChecks}</Text><Text className="metric-label">总打卡数</Text></View>
86	        <View className="metric">
87	          <Text className="metric-value">{streakDays}</Text>
88	          <Text className="metric-label">连续天数</Text>
89	          <Text className="metric-sub">连续精进 {streakDays} 天（完成率≥80%）</Text>
90	        </View>
91	        <View className="metric"><Text className="metric-value">{habits.length}</Text><Text className="metric-label">活跃习惯</Text></View>
92	      </View>
93	
94	      {/* Bar Chart */}
95	      <View className="chart-card">
96	        <Text className="chart-title">每日完成趋势</Text>
97	        <View className="bar-row">
98	          {barData.map((d, i) => (
99	            <View key={i} className="bar-col">
100	              <View className="bar" style={{ height: `${Math.max(d.pct, 4)}%`, background: d.completed > 0 ? "#c4843e" : "#332e28" }} />
101	              <Text className="bar-label">{d.label}</Text>
102	            </View>
103	          ))}
104	        </View>
105	      </View>
106	
107	      {/* Domain Rates */}
108	      <View className="chart-card">
109	        <Text className="chart-title">领域均衡度</Text>
110	        {domainStats.map((d) => (
111	          <View key={d.name} className="domain-row">
112	            <View className="domain-name">
113	              <Icon name={d.icon as import("../../components/Icon").IconName} size={32} color="accent" />
114	              <Text> {d.name}</Text>
115	            </View>
116	            <View className="domain-bar-bg">
117	              <View className="domain-bar-fill" style={{ width: `${d.rate}%`, background: d.color }} />
118	            </View>
119	            <Text className="domain-rate">{d.rate}%</Text>
120	          </View>
121	        ))}
122	      </View>
123	    </View>
124	  );
125	}
126	
127	function countWeekdays(days: number): number {
128	  let count = 0;
129	  const now = new Date();
130	  for (let i = 0; i < days; i++) {
131	    const d = new Date(now);
132	    d.setDate(d.getDate() - i);
133	    const day = d.getDay();
134	    if (day >= 1 && day <= 5) count++;
135	  }
136	  return count;
137	}
138	
139	function calcStreak(habits: HabitWithLogs[]): number {
140	  if (habits.length === 0) return 0;
141	  const dailyHabits = habits.filter((h) => h.frequency === "daily");
142	  if (dailyHabits.length === 0) return 0;
143	  let streak = 0;
144	  const today = new Date(getToday());
145	  for (let i = 0; ; i++) {
146	    const d = new Date(today);
147	    d.setDate(d.getDate() - i);
148	    const dateStr = d.toISOString().split("T")[0];
149	    let completed = 0;
150	    for (const h of dailyHabits) {
151	      const log = h.logs.find((l) => l.date === dateStr);
152	      if (log && log.completed) completed++;
153	    }
154	    const rate = completed / dailyHabits.length;
155	    if (rate >= 0.8) streak++;
156	    else break;
157	  }
158	  return streak;
159	}
